<script>
export default {
  name: "hyjl", // 这个名字推荐：大写字母开头驼峰法命名。
  props: {},
  components: {},
  directives: {},
  mixins: [],
  data() {
    return {
      dataProps: "",
    };
  },
  computed: {},
  created() {},
  mounted() {},
  activated() {},
  deactivated() {},
  watch: {},
  methods: {
    add() {
      console.log("test()--->start()");
      if (!deviceReady) {
        //执行到这边表示cordova环境没有准备好
        return;
      }
      var contact =
        "{'data': [{'group': '开发部','contact': [{'name': '杨1','tel': '13512546000'},{'name': '杨2','tel': '13512546000'},{'name': '杨3','tel': '15512546000'}]},{'group': '策划部','contact': [{'name':'张1','tel': '15368658756'},{'name': '张2','tel': '15368653456'}]}]}";
      alert(contact);
      alert("add");
      //使用这边调用可以获取图像URL[和下面的只能调用一个方法]
      mam.navigator.contactUtils.add(onSuccess, onError, contact);

      function onSuccess(data) {
        console.log("onSuccess() data:" + data);
      }

      //参数为string类型
      function onError(data) {
        console.log("onError() data:" + data);
      }
      console.log("test()--->end()");
    },

    deleteContact() {
      console.log("test()--->start()");
      if (!deviceReady) {
        //执行到这边表示cordova环境没有准备好
        return;
      }
      var contact =
        "{'data': [{'name': '杨1','tel': '13512546000'},{'name':'张1','tel': '15368658756'}]}";
      alert(contact);
      alert("deleteContact");
      //使用这边调用可以获取图像URL[和下面的只能调用一个方法]
      mam.navigator.contactUtils.deleteContact(onSuccess, onError, contact);

      function onSuccess(data) {
        console.log("onSuccess() data:" + data);
      }

      //参数为string类型
      function onError(data) {
        alert(data);
        console.log("onError() data:" + data);
      }
      console.log("test()--->end()");
    },

    openSwitch() {
      console.log("test()--->start()");
      if (!deviceReady) {
        //执行到这边表示cordova环境没有准备好
        return;
      }
      alert("openSwitch");
      //使用这边调用可以获取本地通讯录
      //mam.navigator.openSwitch.openSwitch(onSuccess,onError,"1","11104052");
      mam.navigator.openSwitch.openSwitch(onSuccess, onError, "1", "10025");

      function onSuccess(data) {
        alert(data);
        console.log("onSuccess() data:" + data);
      }

      //参数为string类型
      function onError(data) {
        alert(data);
        console.log("onError() data:" + data);
      }
      console.log("test()--->end()");
    },

    closeSwitch() {
      if (!deviceReady) {
        alert("执行到这边表示cordova环境没有准备好");
        //执行到这边表示cordova环境没有准备好
        return;
      }
      alert("关闭轨迹");
      //使用这边调用可以获取本地通讯录
      mam.navigator.openSwitch.openSwitch(onSuccess1, onError, "0", "10025");
      function onSuccess1(data1) {
        alert(data1);
      }

      //参数为string类型
      function onError(data) {
        alert(data);
        console.log("onError() data:" + data);
      }
      console.log("test()--->end()");
    },

    addExtra() {
      console.log("test()--->start()");
      if (!deviceReady) {
        //执行到这边表示cordova环境没有准备好
        return;
      }
      alert("contractInfos");
      //size 图片大小 单位 bit
      var size = 2 * 1024 * 1024; //此处实在 图片最大 2M
      //拍照 加入定位信息
      mam.navigator.openSwitch.addExtra(onSuccess, onError, size);

      function onSuccess(data) {
        alert(data);
        console.log("onSuccess() data:" + data);
      }

      //参数为string类型
      function onError(data) {
        alert(data);
        console.log("onError() data:" + data);
      }
      console.log("test()--->end()");
    },

    openApk() {
      console.log("test()--->start()");
      if (!deviceReady) {
        //执行到这边表示cordova环境没有准备好
        return;
      }
      alert("openApk");
      //如果是Android写包名
      //如果是IOS写scheme
      var pakName = "com.dlxx.mam.external";
      //使用这边调用可以获取本地通讯录
      mam.navigator.openSwitch.openApk(onSuccess, onError, pakName);

      function onSuccess(data) {
        alert(data);
        console.log("onSuccess() data:" + data);
      }

      //参数为string类型
      function onError(data) {
        alert(data);
        console.log("onError() data:" + data);
      }
      console.log("test()--->end()");
    },

    toGaoDe() {
      console.log("test()--->start()");
      if (!deviceReady) {
        //执行到这边表示cordova环境没有准备好
        return;
      }
      alert("toMap");
      var lon = "118.7715143";
      var lat = "32.05132563";
      //使用这边调用可以获取本地通讯录
      mam.navigator.openSwitch.toMap(onSuccess, onError, lon, lat);

      function onSuccess(data) {
        alert(data);
        console.log("onSuccess() data:" + data);
      }

      //参数为string类型
      function onError(data) {
        alert(data);
        console.log("onError() data:" + data);
      }
      console.log("test()--->end()");
    },
    toBaiDu() {
      console.log("test()--->start()");
      if (!deviceReady) {
        //执行到这边表示cordova环境没有准备好
        return;
      }
      alert("toBaiDu");
      var lon = "118.7715143";
      var lat = "32.05132563";
      //
      mam.navigator.openSwitch.toBaiDu(onSuccess, onError, lon, lat);

      function onSuccess(data) {
        alert(data);
        console.log("onSuccess() data:" + data);
      }

      //参数为string类型
      function onError(data) {
        alert(data);
        console.log("onError() data:" + data);
      }
      console.log("test()--->end()");
    },
     requireImg(url) {
      return require("@/assets/" + url);
    },
  },
};
</script>
